  .replace(/background(?:-color)?:\s*[^;]+;/gi, "background-color: #9bbc0f;")
  .replace(/background:\s*[^;]+;/gi, "background: #9bbc0f;")
  .replace(/color:\s*[^;]+;/gi, "color: #0f380f;");

if (updated === code && !/9bbc0f|0f380f/i.test(code)) {
  throw new Error("No obvious style hook found to patch");
}

const next = typeof widget === "string"
  ? updated
  : { ...widget, code: updated };

if (space.chat.transient.set) {
  await space.chat.transient.set("snake-game", next);
} else if (space.current.transient?.set) {
  await space.current.transient.set("snake-game", next);
} else {
  throw new Error("No transient setter available");
}

return "patched";

