const targets = await (async () => {
  try {
    return await space.api.fileList('L2/', true);
  } catch (e) {
    return [];
  }
})();

const snakeFiles = targets.filter(p => /snake/i.test(p) && /\.(js|jsx|ts|tsx|mjs|cjs)$/.test(p));
const file = snakeFiles[0];
if (!file) throw new Error('Snake source file not found');

const src = await space.api.fileRead(file, 'utf8');
let text = typeof src === 'string' ? src : (src?.text ?? String(src));

const replaced = text
  .replace(/background\s*:\s*['"`]#[0-9a-fA-F]{3,6}['"`]/g, 'background: "#9bbc0f"')
  .replace(/backgroundColor\s*:\s*['"`]#[0-9a-fA-F]{3,6}['"`]/g, 'backgroundColor: "#9bbc0f"')
  .replace(/fillStyle\s*=\s*['"`]#[0-9a-fA-F]{3,6}['"`]/g, 'fillStyle = "#9bbc0f"')
  .replace(/style\s*=\s*\{\{([^}]*)\}\}/g, (m, inner) => {
    if (/background(Color)?\s*:/.test(inner)) {
      return m.replace(/background(Color)?\s*:\s*['"`]#[0-9a-fA-F]{3,6}['"`]/, 'background: "#9bbc0f"');
    }
    return m;
  });

if (replaced === text) {
  throw new Error(`No obvious background color found in ${file}`);
}

await space.api.fileWrite(file, replaced, 'utf8');
return { file, ok: true };

